 1	import type { FC } from 'react';
 2	import { Controller, useFormContext } from 'react-hook-form';
 3	import EmptyCategorySelectOption from 'src/plans/components/EmptyCategorySelectOption';
 4	
 5	import Select from '@components/common/Select';
 6	import { SelectGroup, SelectList, SelectOption } from '@patternfly/react-core';
 7	import { isEmpty } from '@utils/helpers';
 8	import { useForkliftTranslation } from '@utils/i18n';
 9	
10	import { StorageMapFieldId, type StorageMapping } from '../constants';
11	import type { StorageMappingValue } from '../types';
12	
13	type GroupedSourceStorageFieldProps = {
14	  fieldId: string;
15	  storageMappings: StorageMapping[];
16	  usedSourceStorages: StorageMappingValue[];
17	  otherSourceStorages: StorageMappingValue[];
18	};
19	
20	const GroupedSourceStorageField: FC<GroupedSourceStorageFieldProps> = ({
21	  fieldId,
22	  otherSourceStorages,
23	  storageMappings,
24	  usedSourceStorages,
25	}) => {
26	  const {
27	    control,
28	    formState: { isSubmitting },
29	    trigger,
30	  } = useFormContext();
31	  const { t } = useForkliftTranslation();
32	
33	  return (
34	    <Controller
35	      name={fieldId}
36	      control={control}
37	      render={({ field }) => (
38	        <Select
39	          ref={field.ref}
40	          id={fieldId}
41	          isDisabled={isSubmitting}
42	          value={(field.value as StorageMappingValue).name}
43	          onSelect={async (_event, value) => {
44	            field.onChange(value);
45	            await trigger(StorageMapFieldId.StorageMap);
46	          }}
47	          placeholder={t('Select source storage')}
48	        >
49	          <SelectGroup label={t('Storages used by the selected VMs')}>
50	            <SelectList>
51	              {isEmpty(usedSourceStorages) ? (
52	                <EmptyCategorySelectOption resourceName="storages" />
53	              ) : (
54	                usedSourceStorages.map((usedStorage) => (
55	                  <SelectOption
56	                    key={usedStorage.name}
57	                    value={usedStorage}
58	                    isDisabled={storageMappings?.some(
59	                      (mapping: StorageMapping) =>
60	                        mapping[StorageMapFieldId.SourceStorage].name === usedStorage.name,
61	                    )}
62	                  >
63	                    {usedStorage.name}
64	                  </SelectOption>
65	                ))
66	              )}
67	            </SelectList>
68	          </SelectGroup>
69	
70	          <SelectGroup label={t('Other storages present on the source provider')}>
71	            <SelectList>
72	              {isEmpty(otherSourceStorages) ? (
73	                <EmptyCategorySelectOption resourceName="storages" />
74	              ) : (
75	                otherSourceStorages?.map((otherStorage) => (
76	                  <SelectOption
77	                    key={otherStorage.name}
78	                    value={otherStorage}
79	                    isDisabled={storageMappings.some(
80	                      (mapping: StorageMapping) =>
81	                        mapping[StorageMapFieldId.SourceStorage].name === otherStorage.name,
82	                    )}
83	                  >
84	                    {otherStorage.name}
85	                  </SelectOption>
86	                ))
87	              )}
88	            </SelectList>
89	          </SelectGroup>
90	        </Select>
91	      )}
92	    />
93	  );
94	};
95	
96	export default GroupedSourceStorageField;

